/**
 * Integration tests for the full analytics pipeline.
 *
 * Tests the complete flow: HTTP route handlers → AnalyticsService → AnalyticsRepository → Database
 * Also tests event-driven metric collection: EventBus → AnalyticsService → query via handlers.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { AnalyticsRepository } from '../../src/repositories/analytics.repository.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  AnalyticsService,
  resetMetricIdCounter,
} from '../../src/services/analytics.service.js';
import {
  getDashboardHandler,
  getMetricSummaryHandler,
  getTimeSeriesHandler,
  recordMetricHandler,
} from '../../src/routes/analytics.routes.js';
import type {
  DashboardData,
  MetricRecord,
  MetricSummary,
  TimeSeriesPoint,
} from '../../src/models/analytics.js';
import type { AnalyticsErrorResponse } from '../../src/routes/analytics.routes.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

// ---------------------------------------------------------------------------
// Shared setup
// ---------------------------------------------------------------------------

let db: Database;
let repo: AnalyticsRepository;
let eventBus: EventBus;
let service: AnalyticsService;

beforeEach(() => {
  db = new Database();
  repo = new AnalyticsRepository(db);
  eventBus = new EventBus();
  service = new AnalyticsService(repo, eventBus);
  resetMetricIdCounter();
});

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const MARCH_QUERY = {
  startDate: '2026-03-01T00:00:00.000Z',
  endDate: '2026-03-31T23:59:59.999Z',
};

function emitOrder(total: number, timestamp: string, orderId = 'o1', userId = 'u1') {
  return eventBus.emit<OrderCreatedEvent>({
    type: 'order:created',
    order: {
      id: orderId,
      userId,
      items: [],
      total,
      status: 'pending',
      createdAt: new Date(timestamp),
      updatedAt: new Date(timestamp),
    },
    user: {
      id: userId,
      name: 'Test User',
      email: 'test@test.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(timestamp),
  });
}

function emitUserCreated(userId: string, timestamp: string) {
  return eventBus.emit<UserCreatedEvent>({
    type: 'user:created',
    user: {
      id: userId,
      name: 'New User',
      email: `${userId}@test.com`,
      role: 'member',
      createdAt: new Date(timestamp),
      updatedAt: new Date(timestamp),
    },
    timestamp: new Date(timestamp),
  });
}

// ---------------------------------------------------------------------------
// Full pipeline: record via handler → query via handler
// ---------------------------------------------------------------------------

describe('Integration: record then query via handlers', () => {
  it('records a metric and retrieves it in a dashboard', () => {
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 250,
      timestamp: '2026-03-10T12:00:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 150,
      timestamp: '2026-03-15T14:00:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'orders_count',
      value: 1,
      timestamp: '2026-03-10T12:00:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'orders_count',
      value: 1,
      timestamp: '2026-03-15T14:00:00.000Z',
    });

    const result = getDashboardHandler(service, MARCH_QUERY);
    expect(result.statusCode).toBe(200);

    const dashboard = result.body as DashboardData;
    expect(dashboard.metrics).toHaveLength(5);

    const revenue = dashboard.metrics.find((m) => m.metricType === 'revenue')!;
    expect(revenue.currentValue).toBe(400);

    const orders = dashboard.metrics.find((m) => m.metricType === 'orders_count')!;
    expect(orders.currentValue).toBe(2);

    const aov = dashboard.metrics.find((m) => m.metricType === 'average_order_value')!;
    expect(aov.currentValue).toBe(200); // 400/2
  });

  it('records a metric and retrieves it via metric summary handler', () => {
    recordMetricHandler(service, {
      metricType: 'new_users',
      value: 1,
      timestamp: '2026-03-05T10:00:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'new_users',
      value: 1,
      timestamp: '2026-03-20T10:00:00.000Z',
    });

    const result = getMetricSummaryHandler(
      service,
      { metricType: 'new_users' },
      MARCH_QUERY,
    );
    expect(result.statusCode).toBe(200);

    const summary = result.body as MetricSummary;
    expect(summary.metricType).toBe('new_users');
    expect(summary.currentValue).toBe(2);
    expect(summary.timeSeries).toHaveLength(2);
  });

  it('records metrics and retrieves time series via handler', () => {
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 100,
      timestamp: '2026-03-10T08:00:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 50,
      timestamp: '2026-03-10T20:00:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 200,
      timestamp: '2026-03-11T12:00:00.000Z',
    });

    const result = getTimeSeriesHandler(
      service,
      { metricType: 'revenue' },
      { ...MARCH_QUERY, granularity: 'day' },
    );
    expect(result.statusCode).toBe(200);

    const series = result.body as TimeSeriesPoint[];
    expect(series).toHaveLength(2);
    expect(series[0]).toEqual({ timestamp: '2026-03-10T00:00:00.000Z', value: 150 });
    expect(series[1]).toEqual({ timestamp: '2026-03-11T00:00:00.000Z', value: 200 });
  });
});

// ---------------------------------------------------------------------------
// Event-driven pipeline: domain events → automatic metric recording → query
// ---------------------------------------------------------------------------

describe('Integration: event-driven metric collection', () => {
  beforeEach(() => {
    service.registerEventListeners();
  });

  it('order:created events produce revenue and orders_count queryable via dashboard', async () => {
    await emitOrder(99.99, '2026-03-05T10:00:00.000Z', 'o1', 'u1');
    await emitOrder(200.01, '2026-03-10T14:00:00.000Z', 'o2', 'u2');
    await emitOrder(50, '2026-03-20T09:00:00.000Z', 'o3', 'u1');

    const result = getDashboardHandler(service, MARCH_QUERY);
    expect(result.statusCode).toBe(200);

    const dashboard = result.body as DashboardData;
    const revenue = dashboard.metrics.find((m) => m.metricType === 'revenue')!;
    expect(revenue.currentValue).toBe(350);

    const orders = dashboard.metrics.find((m) => m.metricType === 'orders_count')!;
    expect(orders.currentValue).toBe(3);

    const aov = dashboard.metrics.find((m) => m.metricType === 'average_order_value')!;
    expect(aov.currentValue).toBeCloseTo(116.67, 1);
  });

  it('user:created events produce new_users queryable via metric summary', async () => {
    await emitUserCreated('u1', '2026-03-02T10:00:00.000Z');
    await emitUserCreated('u2', '2026-03-15T10:00:00.000Z');
    await emitUserCreated('u3', '2026-03-28T10:00:00.000Z');

    const result = getMetricSummaryHandler(
      service,
      { metricType: 'new_users' },
      MARCH_QUERY,
    );
    expect(result.statusCode).toBe(200);

    const summary = result.body as MetricSummary;
    expect(summary.currentValue).toBe(3);
    expect(summary.timeSeries).toHaveLength(3);
  });

  it('mixed events are queryable together in dashboard', async () => {
    await emitOrder(100, '2026-03-10T12:00:00.000Z', 'o1', 'u1');
    await emitUserCreated('u2', '2026-03-10T14:00:00.000Z');

    const result = getDashboardHandler(service, MARCH_QUERY);
    expect(result.statusCode).toBe(200);

    const dashboard = result.body as DashboardData;
    const revenue = dashboard.metrics.find((m) => m.metricType === 'revenue')!;
    expect(revenue.currentValue).toBe(100);

    const newUsers = dashboard.metrics.find((m) => m.metricType === 'new_users')!;
    expect(newUsers.currentValue).toBe(1);
  });
});

// ---------------------------------------------------------------------------
// Time-range filtering
// ---------------------------------------------------------------------------

describe('Integration: time-range filtering', () => {
  it('only includes metrics within the queried date range', () => {
    // Before range
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 999,
      timestamp: '2026-02-28T23:59:59.999Z',
    });
    // In range
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 100,
      timestamp: '2026-03-15T12:00:00.000Z',
    });
    // After range
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 888,
      timestamp: '2026-04-01T00:00:00.001Z',
    });

    const result = getMetricSummaryHandler(
      service,
      { metricType: 'revenue' },
      MARCH_QUERY,
    );
    expect(result.statusCode).toBe(200);
    expect((result.body as MetricSummary).currentValue).toBe(100);
  });

  it('computes change percent by comparing current and previous periods', () => {
    // Previous period (Feb): Feb 1-28
    recordMetricHandler(service, {
      metricType: 'orders_count',
      value: 10,
      timestamp: '2026-02-15T10:00:00.000Z',
    });
    // Current period (March)
    recordMetricHandler(service, {
      metricType: 'orders_count',
      value: 15,
      timestamp: '2026-03-15T10:00:00.000Z',
    });

    const result = getMetricSummaryHandler(
      service,
      { metricType: 'orders_count' },
      MARCH_QUERY,
    );
    expect(result.statusCode).toBe(200);

    const summary = result.body as MetricSummary;
    expect(summary.currentValue).toBe(15);
    expect(summary.previousValue).toBe(10);
    expect(summary.changePercent).toBe(50); // +50%
  });

  it('supports granularity for time series in dashboard', () => {
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 100,
      timestamp: '2026-03-01T08:00:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 200,
      timestamp: '2026-03-01T09:30:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 50,
      timestamp: '2026-03-01T10:45:00.000Z',
    });

    const result = getTimeSeriesHandler(
      service,
      { metricType: 'revenue' },
      { ...MARCH_QUERY, granularity: 'hour' },
    );
    expect(result.statusCode).toBe(200);

    const series = result.body as TimeSeriesPoint[];
    expect(series).toHaveLength(3);
    expect(series[0]).toEqual({ timestamp: '2026-03-01T08:00:00.000Z', value: 100 });
    expect(series[1]).toEqual({ timestamp: '2026-03-01T09:00:00.000Z', value: 200 });
    expect(series[2]).toEqual({ timestamp: '2026-03-01T10:00:00.000Z', value: 50 });
  });

  it('weekly granularity buckets correctly across days', () => {
    // 2026-03-02 is Monday, 2026-03-09 is Monday
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 100,
      timestamp: '2026-03-02T10:00:00.000Z', // Mon
    });
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 200,
      timestamp: '2026-03-04T10:00:00.000Z', // Wed same week
    });
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 300,
      timestamp: '2026-03-09T10:00:00.000Z', // Next Mon
    });

    const result = getTimeSeriesHandler(
      service,
      { metricType: 'revenue' },
      { ...MARCH_QUERY, granularity: 'week' },
    );
    expect(result.statusCode).toBe(200);

    const series = result.body as TimeSeriesPoint[];
    expect(series).toHaveLength(2);
    expect(series[0]).toEqual({ timestamp: '2026-03-02T00:00:00.000Z', value: 300 });
    expect(series[1]).toEqual({ timestamp: '2026-03-09T00:00:00.000Z', value: 300 });
  });

  it('monthly granularity buckets entire month together', () => {
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 100,
      timestamp: '2026-03-01T10:00:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 200,
      timestamp: '2026-03-15T10:00:00.000Z',
    });
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 300,
      timestamp: '2026-03-31T10:00:00.000Z',
    });

    const result = getTimeSeriesHandler(
      service,
      { metricType: 'revenue' },
      { ...MARCH_QUERY, granularity: 'month' },
    );
    expect(result.statusCode).toBe(200);

    const series = result.body as TimeSeriesPoint[];
    expect(series).toHaveLength(1);
    expect(series[0]).toEqual({ timestamp: '2026-03-01T00:00:00.000Z', value: 600 });
  });
});

// ---------------------------------------------------------------------------
// Error scenarios
// ---------------------------------------------------------------------------

describe('Integration: error scenarios', () => {
  it('returns 400 for missing date parameters on dashboard', () => {
    const result = getDashboardHandler(service, {
      startDate: '',
      endDate: '',
    });
    expect(result.statusCode).toBe(400);
    expect((result.body as AnalyticsErrorResponse).error).toBe('VALIDATION_ERROR');
  });

  it('returns 400 for invalid date format on metric summary', () => {
    const result = getMetricSummaryHandler(
      service,
      { metricType: 'revenue' },
      { startDate: 'yesterday', endDate: 'today' },
    );
    expect(result.statusCode).toBe(400);
    expect((result.body as AnalyticsErrorResponse).error).toBe('VALIDATION_ERROR');
  });

  it('returns 400 for invalid metric type on time series', () => {
    const result = getTimeSeriesHandler(
      service,
      { metricType: 'invalid_metric' as any },
      MARCH_QUERY,
    );
    expect(result.statusCode).toBe(400);
    expect((result.body as AnalyticsErrorResponse).message).toContain('invalid_metric');
  });

  it('returns 400 for endDate before startDate', () => {
    const result = getDashboardHandler(service, {
      startDate: '2026-03-31T00:00:00.000Z',
      endDate: '2026-03-01T00:00:00.000Z',
    });
    expect(result.statusCode).toBe(400);
    expect((result.body as AnalyticsErrorResponse).message).toContain('endDate must be after startDate');
  });

  it('returns 400 for invalid granularity', () => {
    const result = getTimeSeriesHandler(
      service,
      { metricType: 'revenue' },
      { ...MARCH_QUERY, granularity: 'quarter' as any },
    );
    expect(result.statusCode).toBe(400);
    expect((result.body as AnalyticsErrorResponse).message).toContain('granularity');
  });

  it('returns 400 for non-numeric value in recordMetric', () => {
    const result = recordMetricHandler(service, {
      metricType: 'revenue',
      value: 'not-a-number' as any,
    });
    expect(result.statusCode).toBe(400);
    expect((result.body as AnalyticsErrorResponse).message).toContain('value');
  });

  it('returns 400 for missing metricType in recordMetric', () => {
    const result = recordMetricHandler(service, {
      metricType: '' as any,
      value: 10,
    });
    expect(result.statusCode).toBe(400);
  });

  it('returns 400 for invalid timestamp in recordMetric', () => {
    const result = recordMetricHandler(service, {
      metricType: 'revenue',
      value: 10,
      timestamp: 'not-valid',
    });
    expect(result.statusCode).toBe(400);
    expect((result.body as AnalyticsErrorResponse).message).toContain('timestamp');
  });
});

// ---------------------------------------------------------------------------
// Empty/edge cases
// ---------------------------------------------------------------------------

describe('Integration: empty and edge cases', () => {
  it('dashboard returns zero values when no data exists', () => {
    const result = getDashboardHandler(service, MARCH_QUERY);
    expect(result.statusCode).toBe(200);

    const dashboard = result.body as DashboardData;
    expect(dashboard.metrics).toHaveLength(5);
    for (const metric of dashboard.metrics) {
      expect(metric.currentValue).toBe(0);
      expect(metric.previousValue).toBe(0);
      expect(metric.changePercent).toBeNull();
      expect(metric.timeSeries).toEqual([]);
    }
  });

  it('time series returns empty array when no data matches', () => {
    const result = getTimeSeriesHandler(
      service,
      { metricType: 'revenue' },
      MARCH_QUERY,
    );
    expect(result.statusCode).toBe(200);
    expect(result.body).toEqual([]);
  });

  it('multiple recordMetric calls accumulate correctly', () => {
    for (let i = 1; i <= 10; i++) {
      const day = String(i).padStart(2, '0');
      recordMetricHandler(service, {
        metricType: 'revenue',
        value: 10,
        timestamp: `2026-03-${day}T12:00:00.000Z`,
      });
    }

    const result = getMetricSummaryHandler(
      service,
      { metricType: 'revenue' },
      MARCH_QUERY,
    );
    expect(result.statusCode).toBe(200);
    expect((result.body as MetricSummary).currentValue).toBe(100);
    expect((result.body as MetricSummary).timeSeries).toHaveLength(10);
  });

  it('event-driven and manual metrics combine in queries', async () => {
    service.registerEventListeners();

    // Manual record
    recordMetricHandler(service, {
      metricType: 'revenue',
      value: 50,
      timestamp: '2026-03-05T10:00:00.000Z',
    });

    // Event-driven record
    await emitOrder(150, '2026-03-10T10:00:00.000Z', 'o1', 'u1');

    const result = getMetricSummaryHandler(
      service,
      { metricType: 'revenue' },
      MARCH_QUERY,
    );
    expect(result.statusCode).toBe(200);
    expect((result.body as MetricSummary).currentValue).toBe(200);
  });

  it('recordMetric handler returns the persisted record with correct id', () => {
    const r1 = recordMetricHandler(service, {
      metricType: 'revenue',
      value: 100,
      timestamp: '2026-03-01T00:00:00.000Z',
    });
    const r2 = recordMetricHandler(service, {
      metricType: 'revenue',
      value: 200,
      timestamp: '2026-03-02T00:00:00.000Z',
    });

    expect(r1.statusCode).toBe(201);
    expect(r2.statusCode).toBe(201);
    expect((r1.body as MetricRecord).id).toBe('metric-000001');
    expect((r2.body as MetricRecord).id).toBe('metric-000002');

    // Verify both are queryable
    const result = getMetricSummaryHandler(
      service,
      { metricType: 'revenue' },
      MARCH_QUERY,
    );
    expect((result.body as MetricSummary).currentValue).toBe(300);
  });
});

